// --- Icon Map ---

const techIconMap: Record<string, React.ComponentType<IconProps>> = {
  // Backend
  'Java': JavaIcon,
  'Spring Boot': SpringIcon,
  'Microservices': Boxes,
  'PHP': PhpIcon,
  // Frontend
  'JavaScript': JavaScriptIcon,
  'TypeScript': TypeScriptIcon,
  'Next.js': NextjsIcon,
  'Angular': AngularIcon,
  'Vue.js': VueIcon,
  'HTML/CSS': HtmlCssIcon,
  // Database & ERP
  'SQL Server': SqlServerIcon,
  'T-SQL': FileCode2,
  'Stored Procedures': ShieldCheck,
  'Triggers': Zap,
  'Functions': FunctionSquare,
  'SAP Business One': SapIcon,
  // Infrastructure
  'SysAdmin': Terminal,
  'Git': GitIcon,
  'GitHub': GitHubIcon,
  'Mikrotik': MikrotikIcon,
  'TP-Link': TpLinkIcon,
  'Networking': Globe,
  // Fallback for projects
  'Spring Cloud': SpringIcon,
  'PostgreSQL': PostgreSQLIcon,
  'Tailwind CSS': HtmlCssIcon,
  'Framer Motion': Zap,
  'Java Spring Boot': SpringIcon,
};

export function TechIcon({ name, className }: { name: string; className?: string }) {
  const Icon = techIconMap[name];
  if (!Icon) return null;
  return <Icon className={className ?? 'w-3.5 h-3.5'} />;
}

export default techIconMap;
